    public function blog(Request $request)
    {
        $categories = BlogCategory::where('is_active', true)->get();
        $posts = Blog::with('category')
            ->published()
            ->when($request->filled('category'), fn ($q) => $q->whereHas('category', fn ($cq) => $cq->where('slug', $request->category)))
            ->when($request->filled('tag'), fn ($q) => $q->whereJsonContains('tags', $request->tag))
            ->latest()
            ->paginate(9);

        return view('frontend.blog.index', compact('posts', 'categories'));
    }

    public function blogShow(string $slug)
    {
        $post = Blog::with(['category', 'author'])->where('slug', $slug)->published()->firstOrFail();
        $post->increment('views_count');

        $relatedPosts = Blog::with('category')
            ->published()
            ->where('id', '!=', $post->id)
            ->when($post->category_id, fn ($q) => $q->where('category_id', $post->category_id))
            ->latest()
            ->take(3)
            ->get();

        return view('frontend.blog_show', compact('post', 'relatedPosts'));
    }

