    public function storeFreeTrial(Request $request)
    {
        $data = $request->validate([
            'name'           => 'required|string|max:100',
            'email'          => 'required|email',
            'password'       => 'required|string|min:8|confirmed',
            'company_name'   => 'required|string|max:191',
            'phone'          => 'nullable|string|max:20',
            'employee_count' => 'nullable|integer|min:1',
            'agree_terms'    => 'required|accepted',
        ]);

        if (User::where('email', $data['email'])->exists()) {
            return back()->withErrors(['email' => 'Bu e-posta zaten kullanımda'])->withInput();
        }

        $company = Company::create([
            'name'         => $data['company_name'],
            'status'       => 'trial',
            'trial_ends_at' => now()->addDays(14),
        ]);

        $user = User::create([
            'name'              => $data['name'],
            'email'             => $data['email'],
            'password'          => Hash::make($data['password']),
            'company_id'        => $company->id,
            'is_active'         => true,
            'email_verified_at' => now(), // Free trial: immediate access
        ]);

        $isFirstUser = User::count() === 1;
        if ($isFirstUser && \Spatie\Permission\Models\Role::where('name', 'super_admin')->exists()) {
            $user->assignRole('super_admin');
        } else {
            $user->assignRole('company_admin');
        }
        Auth::login($user);

        return redirect()->route('admin.dashboard')
            ->with('success', '14 günlük ücretsiz denemeniz başlatıldı!');
    }
